#include <bits/stdc++.h>
using namespace std;

struct Edge{
	int t,mon;
};

vector<Edge> g[100005];
int n,m,val[100005],a,b,dist[100005];

void SPFA(){
	queue<int> q;
	q.push(a);
	memset(dist,127,sizeof(dist));
	dist[a]=0;
	while(q.size()){
		int f=q.front(),len=g[f].size();
		set<int> r;
		q.pop();
		for(int i=0;i<len;i++)
			if(dist[g[f][i].t]>dist[f]+g[f][i].mon){
				//cout<<g[f][i].t<<' '<<dist[f]+g[f][i].mon<<' ';
				int tmp=r.size();
				r.insert(g[f][i].t);
				if(tmp<r.size())
					q.push(g[f][i].t);
				dist[g[f][i].t]=dist[f]+g[f][i].mon;
			}
		//cout<<endl;
	}
	if(dist[b]<(1<<30))
		cout<<dist[b];
	else
		cout<<"No solution";
}

int main(){
	cin>>n>>m>>a>>b;
	for(int i=0;i<n;i++)
		cin>>val[i];
	for(int i=1;i<=m;i++){
		int u,v;
		cin>>u>>v;
		//cout<<val[v]-val[u]+1<<endl;
		g[u].push_back({v,val[v]-val[u]+1});
	}
	SPFA();
	return 0;
}
